## 1. Generare chei noi
```typescript
import * as ed from '@noble/ed25519';

async function generateKeypair() {
  const privateKey = ed.utils.randomPrivateKey(); // Uint8Array(32)
  const publicKey = await ed.getPublicKeyAsync(privateKey);
  return { privateKey, publicKey };
}
